#include <bits/stdc++.h>
using namespace std;
int n;
double x[16],y[16],dp[16][1<<15];
double dist(double sx,double sy,double ex,double ey){
	return sqrt((sx-ex)*(sx-ex)+(sy-ey)*(sy-ey));
}
int len(int x){
	int sum=0;
	while(x){
		sum+=x&1;
		x>>=1;
	}
	return sum;
}
int main(){
	scanf("%d",&n);
	for(int i=0;i<n;i++)
		scanf("%lf%lf",&x[i],&y[i]);
	for(int i=0;i<n;i++)
		for(int j=0;j<1<<n;j++)
			dp[i][j]=1e9;
	for(int i=0;i<n;i++)
		dp[i][1<<i]=dist(0,0,x[i],y[i]);
	for(int l=2;l<=n;l++)
		for(int s=0;s<1<<n;s++)
			if(len(s)==l)
				for(int i=0;i<n;i++)
					if((1<<i)&s)
						for(int j=0;j<n;j++)
							if((1<<j)&(s-(1<<i)))
								dp[i][s]=min(dp[i][s],dp[j][s-(1<<i)]+dist(x[j],y[j],x[i],y[i]));
	double ans=1e9;
	for(int i=0;i<n;i++)
		ans=min(ans,dp[i][(1<<n)-1]);
	printf("%.2lf",ans);
	return 0;
}
